
require(['app','bootbox'], function(app,bootbox){
app.views.login=Backbone.View.extend({
    defaults: {
          
        sessionId: false,
        authTokenId: null
        
    },
	
    initialize:function(){
        console.log("initializing login view");
        localStorage.removeItem("dataDa");
        localStorage.removeItem("dataA");
        
	},
	events:{
        submit:"login"
    },

    login_home:function(){app.routers.router.prototype.index()},

    render:function(){
       
        $(this.el).html(this.template());
        console.log('evvai login');
          //  Toggle  Password Start
     this.$("#togglePassword").removeClass("fa fa-eye").addClass("fa fa-eye-slash");
     this.$("#togglePassword").click(function() {
        console.log("click togglePassword");
        const passwordInput = $("#password");
        const type = passwordInput.attr("type");

        if (type === "password") {
            console.log("fa fa-eye");
            passwordInput.attr("type", "text");
            $("#togglePassword").removeClass("fa fa-eye-slash").addClass("fa fa-eye");
        } else {
            console.log("fa fa-eye-slash");
            passwordInput.attr("type", "password");
            $("#togglePassword").removeClass("fa fa-eye").addClass("fa fa-eye-slash");
        }
    });
    //  Toggle  Password End
        
        this.$("#loginForm").validate({
            rules:{
                username:{
                    required:true,
                    maxlength:50},
           	password:{
                    required:true,
                    maxlength:20}
            },
            /*  azione:{
            required:true,
            maxlength:20},*/
            messages: this.language.form_messages}
        );
        console.log("azione="+this.$("#azione").val()+  " e.password="+this.$("#password").val());
        $("#username").focus();
        return this;
              
    },

    login:function (event) {
        event.preventDefault(); // Don't let this button submit the form
      

        var that = this;
        
        var jsonObj = this.login_formToJson();
        var _userModel = new app.models.user();
        console.log("jsonObj="+_.keys(jsonObj)+_.values(jsonObj.password)+_.values(jsonObj.azione)+this.$("[name='azione']").val());
        console.log("_userModel="+_.keys(_userModel));
        console.log("_userModel="+_.keys(_userModel.attributes));
        console.log("_userModel="+_.values(_userModel.attributes));
        console.log("_userModel="+_.values(_userModel.cid));
        console.log("navigator.platform="+navigator.platform);
        console.log("navigator.appCodeName="+navigator.appCodeName);
        
  
        _userModel.save(jsonObj,{
     
             
            success: function (model) {
                 
                if (model.changed.success){
                    /** save auth token **/
                    app.global.tokensCollection.each(function(model){model.destroy();});
                   
                    var _model = new app.models.token(model.get('user'));
                    var _session = new app.models.session(model.get('user'));
                    //console.log("_model"+_model.attributes.auth.auth);
                   // console.log(_session.supportStorage);
                    _session.set('tokens',_model.attributes.auth.auth);
                   app.global.tokensCollection.add(_model);
                  
                  
                    
                   _model.save();
                  
                    //sessionStorage.setItem("sessionGLR",app.global.tokensCollection.at(0).get("auth").token);
                   
                    app.routers.router.prototype.dashboard();       
                    //app.routers.router.prototype.index();
                   
                   // console.log(_model);  
                }else
                {
                    console.log(model.changed.success);
                    bootbox.dialog({
                        title: that.language.error_message,
                        message: that.language.error_message,
                        buttons: {
                            main: {
                                label: that.language.label_button,
                                className: "btn btn-danger",
                                callback: function(){
                                    $("body").removeClass("modal-open");
                                }
                            }
                        }
                    });

                } 
                //console.log(_userModel);
              //  console.log(model.changedsuccess);
            },
            error: function(model,response){
                console.log(response);
                console.log(model);
                bootbox.dialog({
                    title: that.language.error_message,
                    message: that.language.error_message,
                    buttons:{
                        main:{
                            label: that.language.label_button,
                            className: "btn btn-danger",
                            callback: function() {
                                $("body").removeClass("modal-open");
                            }
                        }
                    }
                });
                console.log(response);
            },
           // url:'http://localhost/glr_api/login/',
            url:app.global.json_url+'login/',
            //url:app.global.json_url+'app_login.php',
            // url:'./js/php/app_login.php',
            // url: app.const.apiurl() + 'login',
            private: false
        });
       
 
    },//login

   
     	

    login_formToJson:function(){
      //  const crypto = require("crypto");
        console.log($().jquery,Backbone.VERSION,_.VERSION,bootbox.VERSION);
      

      //  var md5 = crypto.createHash('md5').update('Apple').digest('hex');
       /* var sha512 = require('sha512/lib/cryptojs')
        var hash = sha512("hello")
console.log(hash.toString('hex')) */
        var e={};
        e.p="";
      //
      let pp= hex_sha512(this.$("#password").val());
      e.p = hex_sha512(this.$("#password").val());
        // Assicurati che la password non venga inviata in chiaro.
        //this.$("#password").val("") ;
        e.platform=navigator.platform;
        e.appName=navigator.appName;
        e.appVersion=navigator.appVersion;
        e.cookieEnabled=navigator.cookieEnabled;
        e.appCodeName=navigator.appCodeName;
        e.user=this.$("#username").val();
        //e.password=this.$("#password").val();
        e.action=this.$("#azione").val();

                   //    
                //    e.token='';
                //   e.session='';
                 //  e.role='';
          //    console.log("azione="+e.action+" e.password="+e.password);    
        return e;
    },

    
     	
     	destroy_view:function(){this.undelegateEvents();
     		$(this.el).removeData().unbind();
     		this.remove();Backbone.View.prototype.remove.call(this);
     		app.global.loginView=null}
    });
    return app.views.login;
    });